-- ============================================================
-- TIPL Fantasy Cricket — Consolidated Schema
-- Generated by merging migrations 001-028 (excluding stripped features)
-- ============================================================

-- ============================================================
-- CUSTOM TYPES
-- ============================================================
CREATE TYPE player_role AS ENUM ('WK', 'BAT', 'AR', 'BOWL');
CREATE TYPE match_status AS ENUM ('upcoming', 'live', 'completed', 'no_result', 'abandoned');
CREATE TYPE scoring_category AS ENUM ('batting', 'bowling', 'fielding', 'bonus', 'penalty');
CREATE TYPE notification_type AS ENUM ('match_reminder', 'scores_published', 'admin', 'system');

-- ============================================================
-- PROFILES (linked to auth.users)
-- ============================================================
CREATE TABLE profiles (
  id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  display_name TEXT NOT NULL DEFAULT '',
  avatar_url TEXT,
  is_admin BOOLEAN NOT NULL DEFAULT false,
  auto_pick_enabled BOOLEAN NOT NULL DEFAULT false,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

COMMENT ON COLUMN profiles.auto_pick_enabled IS 'If true, system auto-picks team within 2 min of match deadline if user has no selection.';

-- Auto-create profile on signup
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER SET search_path = public
AS $$
BEGIN
  INSERT INTO public.profiles (id, display_name, avatar_url, is_admin, created_at, updated_at)
  VALUES (
    NEW.id,
    COALESCE(NEW.raw_user_meta_data->>'full_name', NEW.raw_user_meta_data->>'name', split_part(NEW.email, '@', 1)),
    COALESCE(NEW.raw_user_meta_data->>'avatar_url', NEW.raw_user_meta_data->>'picture'),
    false,
    NOW(),
    NOW()
  )
  ON CONFLICT (id) DO NOTHING;
  RETURN NEW;
END;
$$;

CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW
  EXECUTE FUNCTION public.handle_new_user();

-- ============================================================
-- TEAMS
-- ============================================================
CREATE TABLE teams (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  short_name TEXT NOT NULL,
  color TEXT NOT NULL DEFAULT '#888888',
  logo_url TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ============================================================
-- PLAYERS
-- ============================================================
CREATE TABLE players (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  team_id UUID NOT NULL REFERENCES teams(id) ON DELETE CASCADE,
  role player_role NOT NULL,
  is_active BOOLEAN NOT NULL DEFAULT true,
  cricapi_id TEXT,
  credit_cost NUMERIC(3,1) NOT NULL DEFAULT 7.0,
  image_url TEXT,
  -- Howstat integration
  howstat_id INTEGER,
  stats_updated_at TIMESTAMPTZ,
  -- Batting stats
  ipl_matches INTEGER,
  ipl_innings INTEGER,
  ipl_runs INTEGER,
  ipl_batting_avg NUMERIC,
  ipl_strike_rate NUMERIC,
  ipl_highest_score TEXT,
  ipl_fifties INTEGER,
  ipl_hundreds INTEGER,
  ipl_fours INTEGER,
  ipl_sixes INTEGER,
  -- Bowling stats
  ipl_wickets INTEGER,
  ipl_bowling_avg NUMERIC,
  ipl_economy NUMERIC,
  ipl_best_bowling TEXT,
  -- Fielding
  ipl_catches INTEGER,
  -- Recent form (last 5 IPL innings scores)
  ipl_recent_scores INTEGER[],
  -- Form indicator for quick display
  form_indicator TEXT DEFAULT 'neutral',
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_players_team ON players(team_id);
CREATE INDEX idx_players_role ON players(role);

-- ============================================================
-- MATCHES
-- ============================================================
CREATE TABLE matches (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  match_number INTEGER NOT NULL UNIQUE,
  team_home_id UUID NOT NULL REFERENCES teams(id),
  team_away_id UUID NOT NULL REFERENCES teams(id),
  venue TEXT NOT NULL DEFAULT '',
  start_time TIMESTAMPTZ NOT NULL,
  status match_status NOT NULL DEFAULT 'upcoming',
  cricapi_match_id TEXT,
  result_summary TEXT,
  live_scores_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_matches_status ON matches(status);
CREATE INDEX idx_matches_start ON matches(start_time);

-- ============================================================
-- PLAYING_XI
-- ============================================================
CREATE TABLE playing_xi (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  match_id UUID NOT NULL REFERENCES matches(id) ON DELETE CASCADE,
  player_id UUID NOT NULL REFERENCES players(id) ON DELETE CASCADE,
  team_id UUID NOT NULL REFERENCES teams(id),
  announced_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE(match_id, player_id)
);

-- ============================================================
-- SELECTIONS
-- ============================================================
CREATE TABLE selections (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  match_id UUID NOT NULL REFERENCES matches(id) ON DELETE CASCADE,
  captain_id UUID REFERENCES players(id),
  vice_captain_id UUID REFERENCES players(id),
  is_auto_pick BOOLEAN NOT NULL DEFAULT false,
  locked_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE(user_id, match_id)
);

CREATE INDEX idx_selections_match ON selections(match_id);
CREATE INDEX idx_selections_user ON selections(user_id);

-- ============================================================
-- SELECTION_PLAYERS (join table)
-- ============================================================
CREATE TABLE selection_players (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  selection_id UUID NOT NULL REFERENCES selections(id) ON DELETE CASCADE,
  player_id UUID NOT NULL REFERENCES players(id) ON DELETE CASCADE,
  UNIQUE(selection_id, player_id)
);

CREATE INDEX idx_selection_players_selection ON selection_players(selection_id);

