-- ============================================================
-- SEASON_LEADERBOARD (materialized view)
-- ============================================================
CREATE MATERIALIZED VIEW season_leaderboard AS
SELECT
  p.id AS user_id,
  p.display_name,
  p.avatar_url,
  COALESCE(SUM(ums.total_points), 0) AS total_points,
  COUNT(ums.id) AS matches_played,
  CASE WHEN COUNT(ums.id) > 0
    THEN ROUND(SUM(ums.total_points) / COUNT(ums.id), 1)
    ELSE 0
  END AS avg_points,
  COUNT(CASE WHEN ums.rank = 1 THEN 1 END) AS first_place_count,
  COUNT(CASE WHEN ums.rank <= 3 THEN 1 END) AS podium_count,
  ROW_NUMBER() OVER (ORDER BY COALESCE(SUM(ums.total_points), 0) DESC) AS season_rank
FROM profiles p
LEFT JOIN user_match_scores ums ON ums.user_id = p.id
GROUP BY p.id, p.display_name, p.avatar_url;

CREATE UNIQUE INDEX idx_leaderboard_user ON season_leaderboard(user_id);

-- ============================================================
-- FUNCTIONS
-- ============================================================

-- Refresh the leaderboard materialized view
CREATE OR REPLACE FUNCTION refresh_leaderboard()
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  REFRESH MATERIALIZED VIEW CONCURRENTLY season_leaderboard;
END;
$$;

-- Auto-lock upcoming matches when start_time has passed
CREATE OR REPLACE FUNCTION public.auto_lock_matches()
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  UPDATE matches
  SET status = 'live', updated_at = NOW()
  WHERE status = 'upcoming'
    AND start_time <= NOW();
END;
$$;

-- Award standings (purple cap, orange cap, mvp)
CREATE OR REPLACE FUNCTION get_award_standings(p_category TEXT, p_limit INTEGER DEFAULT 10)
RETURNS TABLE (
  player_id UUID,
  player_name TEXT,
  team_short_name TEXT,
  team_color TEXT,
  stat_value NUMERIC,
  matches_played BIGINT
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  IF p_category = 'purple_cap' THEN
    RETURN QUERY
      SELECT
        mps.player_id,
        p.name AS player_name,
        t.short_name AS team_short_name,
        t.color AS team_color,
        SUM(mps.wickets)::NUMERIC AS stat_value,
        COUNT(DISTINCT mps.match_id) AS matches_played
      FROM match_player_scores mps
      JOIN players p ON p.id = mps.player_id
      JOIN teams t ON t.id = p.team_id
      GROUP BY mps.player_id, p.name, t.short_name, t.color
      HAVING SUM(mps.wickets) > 0
      ORDER BY stat_value DESC
      LIMIT p_limit;

  ELSIF p_category = 'orange_cap' THEN
    RETURN QUERY
      SELECT
        mps.player_id,
        p.name AS player_name,
        t.short_name AS team_short_name,
        t.color AS team_color,
        SUM(mps.runs)::NUMERIC AS stat_value,
        COUNT(DISTINCT mps.match_id) AS matches_played
      FROM match_player_scores mps
      JOIN players p ON p.id = mps.player_id
      JOIN teams t ON t.id = p.team_id
      GROUP BY mps.player_id, p.name, t.short_name, t.color
      HAVING SUM(mps.runs) > 0
      ORDER BY stat_value DESC
      LIMIT p_limit;

  ELSIF p_category = 'mvp' THEN
    RETURN QUERY
      SELECT
        mps.player_id,
        p.name AS player_name,
        t.short_name AS team_short_name,
        t.color AS team_color,
        SUM(mps.fantasy_points)::NUMERIC AS stat_value,
        COUNT(DISTINCT mps.match_id) AS matches_played
      FROM match_player_scores mps
      JOIN players p ON p.id = mps.player_id
      JOIN teams t ON t.id = p.team_id
      GROUP BY mps.player_id, p.name, t.short_name, t.color
      HAVING SUM(mps.fantasy_points) > 0
      ORDER BY stat_value DESC
      LIMIT p_limit;
  END IF;
END;
$$;

-- Initial refresh of leaderboard
REFRESH MATERIALIZED VIEW season_leaderboard;

